const parts = appsmith.model.installedParts;
function gradeClass(g) {
  if (!g) return 'grade-n';
  const u = g.toUpperCase();
  if (u === 'A') return 'grade-a';
  if (u === 'B') return 'grade-b';
  if (u === 'C') return 'grade-c';
  return 'grade-n';
}
function render(parts) {
  const el = document.getElementById('content');
  if (!parts || parts.length === 0) {
    el.innerHTML = '<p class="empty">No parts installed</p>';
    return;
  }
  let total = 0;
  let hasAny = false;
  const rows = parts.map(p => {
    const cost = p.part_cost ? parseFloat(p.part_cost) : null;
    if (cost !== null) {
      total += cost;
      hasAny = true;
    }
    const spec = p.spec && p.spec !== 'null' && p.spec !== '' ? p.spec : '—';
    const grade = p.condition_grade && p.condition_grade !== 'null' ? p.condition_grade.toUpperCase() : 'N';
    const costStr = cost !== null ? `£${cost.toFixed(2)}` : `<span class="cost-null">—</span>`;
    return `<tr>
      <td><span class="part-ref">${p.part_ref || '—'}</span></td>
      <td>${p.part_type || '—'}</td>
      <td class="spec-cell">${spec}</td>
      <td><span class="grade-badge ${gradeClass(grade)}">${grade}</span></td>
      <td>${costStr}</td>
    </tr>`;
  }).join('');
  const totalLine = hasAny ? `<div class="total-row">Total parts cost <span>£${total.toFixed(2)}</span></div>` : '';
  el.innerHTML = `
    <table class="parts-table">
      <thead><tr>
        <th style="width:90px">Part ref</th>
        <th style="width:130px">Type</th>
        <th>Details</th>
        <th style="width:60px">Grade</th>
        <th style="width:70px">Cost</th>
      </tr></thead>
      <tbody>${rows}</tbody>
    </table>
    ${totalLine}
  `;
}
appsmith.onModelChange(function (model) {
  render(model.installedParts);
});
render(parts);

